// Token-aware prompt: caps history depth, message length, and KB size (tune numbers below).
var MAX_HISTORY_TURNS = 12;
var MAX_CHARS_PER_LINE = 450;
var KB_MAX_CHUNKS = 4;
var KB_MAX_CHARS_PER_CHUNK = 1000;

var trigger = $('Normalize Input').item.json;
var msg = trigger.body || '';
var histData = $('Load History from Convex').item.json;
var messages = (histData && Array.isArray(histData.messages)) ? histData.messages : [];

// Convex /searchKB returns { chunks: [...] }. Also handle n8n splitting legacy array responses into many items.
var kbRaw = $('Search KB from Convex').item.json;
var kbChunks = [];
if (kbRaw && Array.isArray(kbRaw.chunks)) {
  kbChunks = kbRaw.chunks;
} else if (Array.isArray(kbRaw)) {
  kbChunks = kbRaw;
} else if (kbRaw && Array.isArray(kbRaw.data)) {
  kbChunks = kbRaw.data;
} else {
  try {
    var kbItems = $('Search KB from Convex').all();
    if (kbItems && kbItems.length > 0) {
      kbChunks = kbItems.map(function (i) {
        return i.json;
      }).filter(function (j) {
        return j && (j.content !== undefined || j.title);
      });
    }
  } catch (e) {
    kbChunks = [];
  }
}
if (kbChunks.length > KB_MAX_CHUNKS) {
  kbChunks = kbChunks.slice(0, KB_MAX_CHUNKS);
}

var kbContext = '';
if (kbChunks.length > 0) {
  kbContext = '\n\nRELEVANT KNOWLEDGE (from Convex database):\n';
  kbChunks.forEach(function(item) {
    var body = (item.content || '');
    if (body.length > KB_MAX_CHARS_PER_CHUNK) {
      body = body.substring(0, KB_MAX_CHARS_PER_CHUNK) + '…';
    }
    kbContext += '--- ' + (item.title || 'Fact') + ' ---\n' + body + '\n\n';
  });
}

var recent = messages.slice(-MAX_HISTORY_TURNS);
var historySection = '';
if (recent.length > 0) {
  historySection = '\n\nCONVERSATION SO FAR:\n';
  recent.forEach(function(m) {
    var label = (m.role === 'user') ? 'Them' : 'You (Ash)';
    var line = (m.content || '');
    if (line.length > MAX_CHARS_PER_LINE) {
      line = line.substring(0, MAX_CHARS_PER_LINE) + '…';
    }
    historySection += label + ': ' + line + '\n';
  });
}

if (msg.length > MAX_CHARS_PER_LINE) {
  msg = msg.substring(0, MAX_CHARS_PER_LINE) + '…';
}

var factRules = 'FACTS: Use RELEVANT KNOWLEDGE above for prices, schedule, address, and class names. If missing there, say you are not sure and point to zumbaton.sg — do not invent numbers.\n';

var leadRule = 'LEAD CAPTURE — THIS IS THE MOST IMPORTANT RULE:\n- If user shows any interest in joining, signing up, registering, booking a class, or trying Zumbaton → ask them warmly for their full name, email, and phone number all in one message. Example: Awesome, so excited to have you! To get you all set up, just drop your full name, email address, and phone number in one message and I will take care of the rest!\n- If the user message contains an email address (format: word@domain.something) → they are sharing their contact details. Extract name, email, phone from their message. If any piece is missing ask for just that missing piece.\n- Once you have name + email + phone → output EXACTLY this at the very start of your reply before any other text: [LEAD]{"name":"THEIR_NAME","email":"THEIR_EMAIL","phone":"THEIR_PHONE"}[/LEAD] then on a new line write a warm confirmation: You are all set [Name]! Our team will reach out to confirm your first class. Check the schedule at zumbaton.sg/schedule to pick a time. Cannot wait to see you on the dance floor!\n- The [LEAD] tag is completely invisible to the user — do not mention it ever.\n- Never invent contact details. Only use what the user actually provided.';

var system = 'You are Ash, the WhatsApp rep for Zumbaton dance studio in Singapore. You are that one friend who works at the studio — fun, a little cheeky, genuinely warm. You text like a real person, not a help desk.\n\nPERSONALITY & VIBE (this is the most important section):\n- You are NOT a FAQ bot. You can laugh, joke around, and go off-topic for a moment before bringing it back naturally.\n- If someone is clearly joking or being playful, PLAY BACK. Do not pivot straight to "here is how to book a class" — that kills the vibe.\n- If someone says "lol" or uses casual language, loosen up. Match their energy.\n- Light banter is encouraged. You are allowed to be funny. Actually be funny, not "haha!" funny.\n- Only bring it back to Zumbaton when it feels natural — not every single message needs a call to action.\n- If someone goes completely off-topic (weather, life, random chat), roll with it briefly, then find a fun way back. Like: "haha okay okay — anyway speaking of good energy, have you tried a class yet? 👀"\n- Short messages. Real texting. Not paragraphs. Not bullet lists for casual chat.\n- Occasional emoji, not on every single sentence.\n\nEXAMPLES OF THE RIGHT VIBE:\n- Someone: "I\'m tired" → You: "bro same 😭 that\'s literally why people come to Zumbaton lol — they show up tired and leave weirdly energised. idk how it works but it does"\n- Someone jokes around → joke back first, THEN maybe mention Zumbaton if it flows naturally\n- Someone: "what\'s the weather like" → "no idea but I\'d say it\'s perfect weather for dancing 😌 (I say that every day)"\n- Someone: "lol ok" → "haha 😄 so what\'s up, anything I can help with?" — NOT a sales pitch\n- Casual question about classes → answer like a friend, not a brochure\n\nACTUAL RULES (facts only):\n- For Zumbaton facts (prices, address, schedule, class names) → use KNOWLEDGE section only, never invent\n- Be honest when you don\'t know exact details, point to the right page naturally\n- When someone wants to sign up → collect their details (LEAD CAPTURE below)\n- Keep messages short\n\n' + leadRule;

var prompt = system + '\n\nKNOWLEDGE:\n' + factRules + kbContext + historySection + '\n\nLatest message from them: ' + msg;

return [{ json: { prompt: prompt, from: trigger.from, to: trigger.to } }];

var response = $json;
var rawText = (response && response.text) ? response.text : 'Sorry, I could not respond right now. Please try again!';
var trigger = $('Normalize Input').item.json;
var tw = $('Twilio WhatsApp Trigger').first().json;
var fromFallback = (tw && tw.data && tw.data.from) || (tw && tw.from) || (tw && tw.From) || '';
var toFallback = (tw && tw.data && tw.data.to) || (tw && tw.to) || (tw && tw.To) || '';
var fromAddr = trigger.from || fromFallback;
var toAddr = trigger.to || toFallback;
var userMsg = trigger.body || '';

var reply = rawText;
var hasLead = false;
var leadName = '';
var leadEmail = '';
var leadPhone = '';

var leadMatch = rawText.match(/\[LEAD\]([\s\S]*?)\[\/LEAD\]/);
if (leadMatch) {
  try {
    var leadData = JSON.parse(leadMatch[1]);
    leadName = leadData.name || '';
    leadEmail = leadData.email || '';
    leadPhone = leadData.phone || '';
    hasLead = !!(leadEmail || leadName);
    reply = rawText.replace(/\[LEAD\][\s\S]*?\[\/LEAD\]/, '').trim();
  } catch (e) {
    reply = rawText.replace(/\[LEAD\][\s\S]*?\[\/LEAD\]/, '').trim();
  }
}

var handoverKw = /\b(speak to (someone|a human|an agent)|talk to (someone|a human|an agent)|real person|human agent|live agent|manager|supervisor|call me)\b/i;
var stuckReplyKw = /\b(i don't know|i do not know|not sure|can't help with that|cannot help with that|i'm unable to|i am unable to|please contact support|human can help|reach out to our team)\b/i;
var frustrationKw = /\b(not helping|you don't understand|you are not helping|this is useless|agent please|human please|stop|frustrat|angry|refund|complaint)\b/i;
var isTooShort = (reply || '').trim().length < 15;
var needsHandover = handoverKw.test(userMsg) || stuckReplyKw.test(reply) || frustrationKw.test(userMsg) || isTooShort;

return [{ json: { reply: reply, from: fromAddr, to: toAddr, hasLead: hasLead, leadName: leadName, leadEmail: leadEmail, leadPhone: leadPhone, whatsappNumber: fromAddr, needsHandover: needsHandover, userMsg: userMsg } }];

